// STRUCTURE: clean each email down to the parts that matter.
// Strips HTML, grabs subject/sender/snippet and a best-effort source URL.
function stripHtml(html = '') {
  return html
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}
function firstRealUrl(html = '') {
  const m = html.match(/https?:\/\/[^"'\s>]+/g) || [];
  // skip common tracking / unsubscribe hosts
  const skip = /(unsubscribe|list-manage|sendgrid|mailchimp|beehiiv\.com\/c\/|click\.|track|utm_)/i;
  const real = m.find(u => !skip.test(u));
  return real || (m[0] || '');
}
const emails = [];
for (const item of $input.all()) {
  const d = item.json;
  const body = d.textPlain || stripHtml(d.textHtml || d.snippet || '');
  emails.push({
    subject: d.subject || '(no subject)',
    from: (d.from && d.from.value && d.from.value[0] && d.from.value[0].name) || d.from || 'Unknown',
    snippet: body.slice(0, 1200), // cap to control token cost
    mainUrl: firstRealUrl(d.textHtml || '')
  });
}
return [{ json: { emails } }];

